import{_ as a,c as r,o as t,af as o}from"./chunks/framework.DcbXK6Cz.js";const p=JSON.parse('{"title":"常见问题（FAQ）","description":"","frontmatter":{"sidebar":[{"text":"快速开始","link":"/guide/quickstart"},{"text":"功能详解","link":"/guide/menu"},{"text":"插件与扩展","link":"/guide/plugins"},{"text":"常见问题","link":"/faq"},{"text":"关于作者","link":"/about"}]},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),n={name:"guide/faq.md"};function i(d,e,s,l,c,h){return t(),r("div",null,e[0]||(e[0]=[o('<h1 id="常见问题-faq" tabindex="-1">常见问题（FAQ） <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题（FAQ）&quot;">​</a></h1><h2 id="termux-相关" tabindex="-1">Termux 相关 <a class="header-anchor" href="#termux-相关" aria-label="Permalink to &quot;Termux 相关&quot;">​</a></h2><p><strong>Q：为何不能用 Play 商店版 Termux？</strong><br> A：Google Play 版已停止维护且缺少核心组件，可能导致脚本无法运行。请使用GitHub / F-Droid 版本。</p><p><strong>Q：首次运行脚本提示“存储权限不足”怎么办？</strong><br> A：请务必授予 Termux 存储权限，否则部分导入/导出功能将无法使用。</p><hr><h2 id="安装-运行故障" tabindex="-1">安装/运行故障 <a class="header-anchor" href="#安装-运行故障" aria-label="Permalink to &quot;安装/运行故障&quot;">​</a></h2><p><strong>Q：脚本运行报错或网络下载失败？</strong><br> A：请检查网络环境，确保可访问 GitHub。如多次报错，请截图报错信息，并加入 QQ 群 <code>807134015</code> 获取帮助。</p><p><strong>Q：如何修复依赖/恢复脚本？</strong><br> A：菜单 <code>5. 系统维护</code> → <code>2. 修复依赖环境</code>，自动补全缺失依赖。</p><p><strong>Q：升级失败怎么办？</strong><br> A：建议重启 Termux，再进入菜单 <code>6. 脚本管理</code> 选择“菜单脚本更新”。</p><hr><h2 id="数据管理" tabindex="-1">数据管理 <a class="header-anchor" href="#数据管理" aria-label="Permalink to &quot;数据管理&quot;">​</a></h2><p><strong>Q：如何备份角色卡和聊天记录？</strong><br> A：主菜单 <code>5. 系统维护</code> → <code>3. 导出酒馆数据</code>，备份将自动保存到下载目录。</p><p><strong>Q：如何恢复备份？</strong><br> A：将备份 <code>.zip</code> 文件置于手机“下载”目录，在菜单选择对应“导入”，按提示操作即可。</p><hr><h2 id="插件相关" tabindex="-1">插件相关 <a class="header-anchor" href="#插件相关" aria-label="Permalink to &quot;插件相关&quot;">​</a></h2><p><strong>Q：插件有安全风险吗？</strong><br> A：第三方插件如“酒馆助手”允许自定义 JS，存在潜在风险。务必只安装信任来源的插件。</p><hr><h2 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to &quot;其他问题&quot;">​</a></h2><p><strong>Q：如何联系作者或加入交流群？</strong><br> A：详见 <a href="/guide/about.html">关于作者</a>。</p>',19)]))}const g=a(n,[["render",i]]);export{p as __pageData,g as default};
